def pre(i):
    # Input must be a tuple (tokens, N)
    if not isinstance(i, tuple) or len(i) != 2:
        return False
    tokens, N = i
    # tokens must be a list of integers
    if not isinstance(tokens, list):
        return False
    if not all(isinstance(t, int) for t in tokens):
        return False
    # N must be a non‑negative integer
    if not isinstance(N, int) or N < 0:
        return False
    return True


def post(i, o):
    # Output must be correct for a valid input
    if not pre(i):
        return False
    tokens, N = i
    expected = tokens[:min(N, len(tokens))]
    return isinstance(o, list) and o == expected
